+      console.log(chalk.gray('  •'), item);
+    });
+  },
+
+  table(data: Record<string, string>): void {
+    const maxKeyLength = Math.max(...Object.keys(data).map(k => k.length));
+    Object.entries(data).forEach(([key, value]) => {
+      console.log(
+        chalk.gray('  '),
+        chalk.white(key.padEnd(maxKeyLength)),
+        chalk.gray(':'),
+        chalk.cyan(value)
+      );
+    });
+  }
